  "reader.articles.postgraduate-open-day-2026": {
    "key": "reader.articles.postgraduate-open-day-2026",
    "appId": "reader",
    "subroute": "articles/postgraduate-open-day-2026",
    "title": "Open Day 2019",
    "excerpt": "Come and visit the Computer Science stall at the University’s open on Saturday 23 February. Our staff and postgraduate students will be available all day from 8:30–16:00 to answer…",
    "shell": "default",
    "meta": {
      "sort_order": "3",
      "card_badge": "Newsfeed",
      "card_image": "/cs-assets/newsfeed/openday2019.jpg",
      "source_url": "https://cs.sun.ac.za/newsfeed/2019/02/21/openday.html",
      "source_mirrored_at": "2026-03-03"
    },
    "html": "<div class=\"newsitem\"><h1>Open Day 2019</h1><div class=\"newsdate\"><span class=\"day\"> Thursday </span><span class=\"date\"> 21 </span><span class=\"month\">February</span><span class=\"year\">2019</span></div><p><img src=\"/cs-assets/newsfeed/openday2019.jpg\" alt=\"Open Day\"></p><p>Come and visit the Computer Science stall at the University’s open on Saturday 23 February. Our staff and postgraduate students will be available all day from 8:30–16:00 to answer any questions you might have about studying Computer Science at Stellenbosch.</p><p>Our stall is in the JC Smuts Building and there are also two talks from industry partners at 9:00–9:45 and at 14:00–14:45 in the Mathematical Sciences Building, Room 1005.</p></div>\n",
    "sections": [
      {
        "key": "000-main",
        "slot": "main",
        "html": "<div class=\"newsitem\"><h1>Open Day 2019</h1><div class=\"newsdate\"><span class=\"day\"> Thursday </span><span class=\"date\"> 21 </span><span class=\"month\">February</span><span class=\"year\">2019</span></div><p><img src=\"/cs-assets/newsfeed/openday2019.jpg\" alt=\"Open Day\"></p><p>Come and visit the Computer Science stall at the University’s open on Saturday 23 February. Our staff and postgraduate students will be available all day from 8:30–16:00 to answer any questions you might have about studying Computer Science at Stellenbosch.</p><p>Our stall is in the JC Smuts Building and there are also two talks from industry partners at 9:00–9:45 and at 14:00–14:45 in the Mathematical Sciences Building, Room 1005.</p></div>\n"
      }
    ]
  },
